#include <vector>
#include <unordered_map>
#include <algorithm>

using namespace std;

bool solve(vector<long long> nums, long long k) {
    unordered_map<long long, long long> freq;
    for (long long num : nums) {
        freq[num]++;
    }

    long long max_freq = 0;
    for (auto& pair : freq) {
        if (pair.second > max_freq) {
            max_freq = pair.second;
        }
    }

    return max_freq * k <= nums.size();
}
